export const COMPONENTS: ReadonlyArray<ComponentEntry> = [
  { name: "abbr", tag: "ce-abbr", className: "CeAbbr", import: "custom-elements-collection/abbr", category: "ui", group: "Layout & primitives", description: "Inline abbreviation glyph (e.g. 'API', 'WWW') with the full text exposed via the native title tooltip and aria-label. The host carries tabindex=0 so the expansion is reachable via keyboard. Shadow DOM only because the dotted underline uses the standardised :host styling." },
  { name: "accordion", tag: "ce-accordion", className: "CeAccordion", import: "custom-elements-collection/accordion", category: "ui", group: "Layout & primitives", description: "Multi-disclosure companion to ce-details. Accepts JSON items ({summary, body?, count?, open?, id?}) or slotted <details> / <ce-details> children (CDR-005). Static-by-default — items render with their initial open state and toggle via native <details>; the component tracks open state internally for ergonomic event payloads. When `single` is set, opening one row closes all others (radio-style FAQ pattern). Emits ce-accordion-change with the array of currently-open ids." },
  { name: "affix", tag: "ce-affix", className: "CeAffix", import: "custom-elements-collection/affix", category: "ui", group: "Layout & primitives", description: "Pure-CSS sticky wrapper for toolbar headers, bottom docks, and side-rail TOCs. Accepts any CSS length for the offset and uses logical inset properties (inset-inline-start/end) for RTL-safe start/end edges." },
  { name: "attachment-strip", tag: "ce-attachment-strip", className: "CeAttachmentStrip", import: "custom-elements-collection/attachment-strip", category: "ui", group: "Chat surfaces", description: "Horizontal scrolling row of attachment tiles placed above a chat input. Each tile shows a thumbnail (for images) or a kind icon (file, audio, video, other), the filename, and an optional size label. A ✕ button on each tile fires `ce-attachment-remove`; the host updates its source-of-truth. Accepts data as a JSON `items` attribute (CDR-005 JSON mode) or as slotted custom tiles when `items` is empty (CDR-005 slot mode)." },
  { name: "avatar", tag: "ce-avatar", className: "CeAvatar", import: "custom-elements-collection/avatar", category: "ui", group: "Layout & primitives", description: "Compact identity primitive. Renders an <img> when src is provided; otherwise derives monogram initials from name (up to two tokens). Falls back to an empty neutral disc when neither is given. Three sizes (sm/md/lg) and two shapes (circle/square). The initials fallback accepts an optional CecColor tint for category-coded teams or roles." },
  { name: "avatar-group", tag: "ce-avatar-group", className: "CeAvatarGroup", import: "custom-elements-collection/avatar-group", category: "ui", group: "Layout & primitives", description: "Container for ce-avatar (or arbitrary HTML) children that visually overlaps each child by a configurable amount and renders a +N chip in their stead once the total exceeds max. Propagates its size attribute to size-aware ce-avatar children for consistent sizing." },
  { name: "badge", tag: "ce-badge", className: "CeBadge", import: "custom-elements-collection/badge", category: "ui", group: "Layout & primitives", description: "Notification-style count badge that anchors to slotted content. Clamps to a configurable max with a '+' suffix, supports a dot variant for unread state, and uses semantic color variants." },
  { name: "bar-chart", tag: "ce-bar-chart", className: "CeBarChart", import: "custom-elements-collection/bar-chart", category: "ui", group: "Metrics & charts", description: "Horizontal bar chart accepting a JSON-attribute or property-bound array (data=[]) OR slotted <ce-bar-row> children (CDR-005). Resolution order: data non-empty → use it; else iterate ce-bar-row slot children; else show empty state. Both modes produce visually identical output for equivalent data. Non-ce-bar-row slot children are passed through to light DOM and ignored by the data path (CDR-006). Auto-scales when max is unset, renders ARIA progressbars per row, and routes color through the shared resolveColor() helper so per-row color accepts both named tokens (\"blue\", \"green\", …) and arbitrary CSS values. Each row is keyboard-focusable and emits ce-chart-hover / ce-chart-leave / ce-chart-select. Optional gridlines and sparkline modes." },
  { name: "bar-row", tag: "ce-bar-row", className: "CeBarRow", import: "custom-elements-collection/bar-row", category: "ui", group: "Metrics & charts", description: "Carries a numeric value (0..max), optional color, rich label slot, and meta slot. When nested inside ce-bar-chart the parent reads value/color as attributes and consumes the label/meta slot HTML via querySelectorAll — the row renders nothing (display:contents). When used standalone it renders a complete single-row bar with ARIA progressbar semantics, label, animated fill, and meta. The value-display attribute controls where the numeric value appears: inside the fill (default), outside to the right, or hidden. Rich label/meta content is supported per CDR-002: the slots can carry <span>, <a>, <ce-chip>, or any inline element." },
  { name: "bookmark", tag: "ce-bookmark", className: "CeBookmark", import: "custom-elements-collection/bookmark", category: "ui", group: "Feedback", description: "Single boolean switch for save/shortlist/pin semantics. Reflects active to the host attribute and surfaces ARIA role=switch with aria-checked. Clicking the host or pressing Enter/Space toggles state and dispatches a bubbling ce-bookmark-change event. Slotted icon and label slots let consumers override the emoji defaults." },
  { name: "breadcrumbs", tag: "ce-breadcrumbs", className: "CeBreadcrumbs", import: "custom-elements-collection/breadcrumbs", category: "ui", group: "Layout & primitives", description: "Static navigation primitive. Accepts both shapes (CDR-005): a JSON items array of { label, href? } or slotted <a>/<span> children. In JSON mode the last item is rendered as the current-page text (or a link if href is present but it's still flagged aria-current=page). In slot mode the last child gets the current styling via ::slotted(:last-child); the component assigns named slot positions on slotchange and renders the configured separator between crumbs." },
  { name: "button", tag: "ce-button", className: "CeButton", import: "custom-elements-collection/button", category: "ui", group: "Forms", description: "Themable action button. Wraps a native <button> so keyboard, focus, and form-submit behavior come for free; emits ce-click in addition. Loading state replaces the label with a spinner and blocks activation. Accepts an icon attribute or a named `icon` slot for arbitrary glyphs/SVG." },
  { name: "callout", tag: "ce-callout", className: "CeCallout", import: "custom-elements-collection/callout", category: "ui", group: "Layout & primitives", description: "Tinted left-border admonition box. Replaces drift between callout / admonition / alert / note / risk markup. Five semantic types color-code the border and background; an optional title overrides via attribute or named slot." },
  { name: "card", tag: "ce-card", className: "CeCard", import: "custom-elements-collection/card", category: "ui", group: "Layout & primitives", description: "Generic content card with title, body, and footer slots. Supports a colored left-border accent, hover-elevation, compact padding, and a clickable mode that adds role=button + Enter/Space activation and emits ce-card-activate." },
  { name: "center", tag: "ce-center", className: "CeCenter", import: "custom-elements-collection/center", category: "ui", group: "Layout & primitives", description: "Wraps content in a max-width block centered with margin-inline:auto and inline padding (gutter). Supports four width presets in ch units and an intrinsic mode that also centers block-direction children via flex column." },
  { name: "chart", tag: "ce-chart", className: "CeChart", import: "custom-elements-collection/chart", category: "ui", group: "Metrics & charts", description: "Lazy-loaded Chart.js wrapper. On first update injects a <script src=…> for Chart.js if window.Chart is not already present, then mounts a chart on a managed canvas. Honors live updates to type / data / options by destroying and re-mounting. Renders an inline error block if the script fails to load." },
  { name: "chat-bubble", tag: "ce-chat-bubble", className: "CeChatBubble", import: "custom-elements-collection/chat-bubble", category: "ui", group: "Chat surfaces", description: "Single LLM-chat message bubble. The role attribute drives color tinting (assistant=blue, user=purple, system=neutral, tool=amber) and avatar placement (user-aligned right; everyone else left). Header surfaces author + model + timestamp; footer surfaces a slotted footer + an optional tokens count. Pure presentation; emits no events." },
  { name: "chat-input", tag: "ce-chat-input", className: "CeChatInput", import: "custom-elements-collection/chat-input", category: "ui", group: "Chat surfaces", description: "A self-contained chat composer widget that grows the textarea as the user types (up to max-rows), emits ce-chat-submit on Enter or send-button click, switches to a stop button while busy, and optionally renders an attach button. All buttons and icons are overrideable via named slots." },
  { name: "check-item", tag: "ce-check-item", className: "CeCheckItem", import: "custom-elements-collection/check-item", category: "ui", group: "Forms", description: "Carries id, checked, and category attributes. Default slot accepts rich content — links, chips, code, dates — per CDR-002. When nested inside ce-checklist the parent reads attributes via DOM and renders the slot HTML; the item itself renders nothing (display:contents). Standalone renders a single checkbox + label row." },
  { name: "checkbox", tag: "ce-checkbox", className: "CeCheckbox", import: "custom-elements-collection/checkbox", category: "ui", group: "Forms", description: "Three-state checkbox (unchecked / checked / indeterminate). Indeterminate is a visual middle state used for parent rows of partially-selected groups; toggling clears it and selects the box. Carries role=checkbox + aria-checked (true/false/mixed) and supports Space and Enter to toggle." },
  { name: "checklist", tag: "ce-checklist", className: "CeChecklist", import: "custom-elements-collection/checklist", category: "ui", group: "Forms", description: "Markdown-style task list rendered as native checkboxes. Without persist-key, this is a static read-only display — no localStorage writes happen and no mutation events fire. Items may be supplied as a JSON attribute (items prop) or as <ce-check-item> slot children per CDR-005 (resolution order: JSON prop non-empty → slot children → empty state). Setting persist-key mirrors state to localStorage so progress survives reloads. With allow-edit, a small input appears so users can append new items inline. With group-by=\"category\", items are rendered under <h4> section headers." },
  { name: "chip", tag: "ce-chip", className: "CeChip", import: "custom-elements-collection/chip", category: "ui", group: "Layout & primitives", description: "Small inline status indicator. Replaces ad-hoc badge / pill / tag / label markup with one canonical element. Seven color types (neutral / green / red / amber / blue / purple / cyan), optional leading dot, and an outlined treatment for low-emphasis use." },
  { name: "citation", tag: "ce-citation", className: "CeCitation", import: "custom-elements-collection/citation", category: "ui", group: "Chat surfaces", description: "Inline citation marker that renders as [index] superscript by default and reveals a popover with expanded source context on hover or keyboard focus. Becomes an anchor when href is set; remains a focusable span otherwise. Uses ARIA role=doc-noteref + a tooltip popover wired via aria-describedby." },
  { name: "clock", tag: "ce-clock", className: "CeClock", import: "custom-elements-collection/clock", category: "ui", group: "Dashboard", description: "Live clock with absolute, relative ('5 minutes ago'), or combined display. Time-zone aware via the IANA `tz` attribute and Intl.DateTimeFormat; relative-time uses Intl.RelativeTimeFormat seeded from the `since` ISO timestamp. The internal interval can be disabled by setting tick-ms to 0 for snapshot-style use." },
  { name: "code", tag: "ce-code", className: "CeCode", import: "custom-elements-collection/code", category: "ui", group: "Comparison & narrative", description: "Code block component. Header row shows an optional filename (left) and language label (right) plus a copy button when copy=true. Body is a <pre><code> with the slotted code text. The copy button uses navigator.clipboard with a hidden-textarea fallback and emits ce-code-copy on success." },
  { name: "combobox", tag: "ce-combobox", className: "CeCombobox", import: "custom-elements-collection/combobox", category: "ui", group: "Forms", description: "Form-associated combobox combining a text input with a filterable popup listbox. Accepts options via a JSON data attribute or slotted ce-option children (CDR-005). Supports keyboard navigation, allow-custom mode for free-text entry, loading state, and full ARIA combobox pattern. Emits ce-change on selection." },
  { name: "comment", tag: "ce-comment", className: "CeComment", import: "custom-elements-collection/comment", category: "ui", group: "Feedback", description: "Compact-by-default comment input. Collapsed: a small button. Clicking expands to a textarea that auto-grows between min-rows and max-rows by computed scrollHeight. Typing emits debounced ce-comment-change events; explicit submission (per submit-on) emits ce-comment-commit. Supports submit-on blur, enter, cmd-enter, or manual. Auto-collapses on submit unless submit-on=manual; Cancel and Escape collapse without committing." },
  { name: "compare", tag: "ce-compare", className: "CeCompare", import: "custom-elements-collection/compare", category: "ui", group: "Comparison & narrative", description: "Side-by-side comparison panel. Left column gets a red tint (Before), right column a green tint (After), and a center column shows a configurable arrow (default → ). Below 640px the layout collapses to a single column and the arrow hides." },
  { name: "confirm", tag: "ce-confirm", className: "CeConfirm", import: "custom-elements-collection/confirm", category: "ui", group: "Forms", description: "Lightweight confirmation row used in place of an OS-level confirm dialog. Two buttons with semantic primary/secondary styling; danger variant tints the surface and primary button. Emits ce-confirm or ce-cancel; the host has role=alertdialog with the prompt as aria-label." },
  { name: "conversation-tree", tag: "ce-conversation-tree", className: "CeConversationTree", import: "custom-elements-collection/conversation-tree", category: "ui", group: "Chat surfaces", description: "Inline pill control rendering a prev arrow, an index/total counter, and a next arrow. Used to switch among forked or regenerated responses in chat surfaces. Emits ce-branch-prev / ce-branch-next on directional clicks plus a unified ce-branch-select on every change. Supports ArrowLeft / ArrowRight keyboard navigation when focused." },
  { name: "copy-button", tag: "ce-copy-button", className: "CeCopyButton", import: "custom-elements-collection/copy-button", category: "ui", group: "Chat surfaces", description: "A button paired with another element by `for=<id>` (or selector). Reads the target's textContent (or input/textarea value), writes it to the system clipboard via the Clipboard API, and falls back to a hidden textarea + execCommand path when the modern API is unavailable. The button briefly switches to the copied-label and dispatches ce-copy { text, ok }." },
  { name: "countdown", tag: "ce-countdown", className: "CeCountdown", import: "custom-elements-collection/countdown", category: "ui", group: "Layout & primitives", description: "Live countdown timer. Renders the remaining time as colon-separated segments (days, hours, minutes, seconds) sized to format: 'dhms' auto-trims a leading 0-day, 'hms' rolls days into hours, 'ms' rolls hours into minutes, and 's' renders a pure seconds count. Optional inline labels under each segment for marketing-style countdowns. Fires ce-countdown-end exactly once when the remaining time hits zero and stops its internal timer." },
  { name: "counter", tag: "ce-counter", className: "CeCounter", import: "custom-elements-collection/counter", category: "ui", group: "Dashboard", description: "Display a number that smoothly animates to a target value when set, with optional prefix/suffix decorations and a trend caret. Uses requestAnimationFrame with ease-out-cubic; setting duration-ms to 0 disables animation. Distinct from <ce-kpi>: counter focuses on motion + numeric updates, while kpi focuses on labelled metric layout." },
  { name: "cursor", tag: "ce-cursor", className: "CeCursor", import: "custom-elements-collection/cursor", category: "ui", group: "Chat surfaces", description: "A purely visual blinking caret used by chat surfaces while assistant tokens are arriving. Three shapes (bar, block, underline) and a configurable blink interval; no slots, no events, no state." },
  { name: "date-picker", tag: "ce-date-picker", className: "CeDatePicker", import: "custom-elements-collection/date-picker", category: "ui", group: "Forms", description: "Form primitive that delegates date / time parsing, keyboard handling, and the calendar popup to the browser's native input. Mirrors ce-input's label / help / error / prefix / suffix layout for consistency across the forms group. The `type` attribute switches between date (default), time, datetime-local, month, and week. min, max, step are forwarded as-is. Emits ce-input per keystroke and ce-change on commit." },
  { name: "decision-tree", tag: "ce-decision-tree", className: "CeDecisionTree", import: "custom-elements-collection/decision-tree", category: "ui", group: "Comparison & narrative", description: "Single-level decision tree component for if/then teaching diagrams. Renders a centered question and a responsive grid of branches; each branch declares yes / no / neutral kind, gets a tinted border + arrow label (↓ YES / ↓ NO / ↓), and shows label and result text. **Limitation: single-level only** — for multi-level hierarchical trees, use plain `<ul>/<li>` or a future `ce-tree`." },
  { name: "details", tag: "ce-details", className: "CeDetails", import: "custom-elements-collection/details", category: "ui", group: "Layout & primitives", description: "Thin wrapper over native <details> with chevron rotation, hover state, an optional right-aligned count chip, and a custom toggle event. Reflects open to the host attribute so consumers can style or query collapsed state." },
  { name: "diff", tag: "ce-diff", className: "CeDiff", import: "custom-elements-collection/diff", category: "ui", group: "Content", description: "Compact LCS-based diff viewer for code review surfaces and PR comments. Choose unified (single column with +/−/ space markers) or split (two columns side-by-side). Header surfaces the language label and the add/delete summary. The LCS algorithm runs in O(n × m) so it's intended for short-to-medium diffs (a few hundred lines)." },
  { name: "dismiss", tag: "ce-dismiss", className: "CeDismiss", import: "custom-elements-collection/dismiss", category: "ui", group: "Feedback", description: "Switch-semantic toggle for hide/drop semantics — the visual sibling to ce-bookmark with reversed defaults. When active, also sets data-ce-dismissed=true on the nearest ce-feedback-bar ancestor so consumers can dim the entire row via a CSS rule. Tolerates absence of an ancestor bar." },
  { name: "divider", tag: "ce-divider", className: "CeDivider", import: "custom-elements-collection/divider", category: "ui", group: "Layout & primitives", description: "Lightweight separator primitive. With no slotted content the rule is a continuous 1px line; with a slotted label the rule splits into two equal segments framing the label. Vertical orientation switches to a 1px inline column suitable for separating inline groups. The inset attribute pulls the rule away from container edges (none / sm / md / lg). Reads as role=separator to assistive tech." },
  { name: "donut", tag: "ce-donut", className: "CeDonut", import: "custom-elements-collection/donut", category: "ui", group: "Metrics & charts", description: "Inline SVG donut/pie. Provide a JSON array of segment values, optional colors and labels, and an optional center label or `center` slot to fill the hole. Setting thickness=0 turns it into a pie. Best for 3-6 segments; for ranked breakdowns prefer ce-bar-chart." },
  { name: "drawer", tag: "ce-drawer", className: "CeDrawer", import: "custom-elements-collection/drawer", category: "ui", group: "Layout & primitives", description: "A sliding panel anchored to one of the four viewport edges. In modal mode wraps a native <dialog> with showModal() for automatic focus trap, scrim, and Escape handling. In non-modal mode uses a positioned div. Supports four sides, four sizes, an optional scrim dismiss guard, trigger slot, header/body/footer slots, and programmatic show/hide/toggle methods." },
  { name: "dropdown-menu", tag: "ce-dropdown-menu", className: "CeDropdownMenu", import: "custom-elements-collection/dropdown-menu", category: "ui", group: "Layout & primitives", description: "A multi-element component: ce-dropdown-menu (parent), ce-menu-item, ce-menu-separator, and ce-menu-group. The parent uses the native Popover API (popover=auto) for top-layer rendering and built-in light-dismiss. JS positioning handles 6 placement values. Keyboard navigation follows the ARIA menu pattern: ArrowDown/Up navigate, Enter/Space activate, Escape closes, Home/End jump to first/last. Emits ce-menu-select with the activated item's value." },
  { name: "duration", tag: "ce-duration", className: "CeDuration", import: "custom-elements-collection/duration", category: "ui", group: "Layout & primitives", description: "Pure formatter for a fixed elapsed time — e.g. 'this task took 3725 seconds → 1h 2m'. Auto-picks the most significant units (days, hours, minutes, seconds) up to a cap (default 2). The compact format renders '1h 2m 5s'; the long format renders '1 hour 2 minutes 5 seconds' with correct plural agreement. Sub-second durations supplied via the ms attribute are formatted as a millisecond string. No live ticking — for a counting timer see ce-countdown, for relative age see ce-relative-time." },
  { name: "empty-state", tag: "ce-empty-state", className: "CeEmptyState", import: "custom-elements-collection/empty-state", category: "ui", group: "Feedback", description: "Centred column layout. Renders an optional circular icon badge (or a caller-supplied illustration), a title slot (caller controls heading level), a body description slot, an actions slot for CTA buttons, and an optional collapsible details slot for technical detail (e.g., error codes). Three size variants (sm/md/lg) scale spacing. The severity attribute (none/success/error/info/warning) adds a tinted panel and auto-derived icon glyph — covering the former ce-result use cases. Host carries role=status for live-region accessibility." },
  { name: "example", tag: "ce-example", className: "CeExample", import: "custom-elements-collection/example", category: "ui", group: "Comparison & narrative", description: "Color-coded example block. type=good tints green and labels 'Good'; type=bad tints red and labels 'Wrong'; type=neutral uses a neutral border and labels 'Example'. Consumers can override the label text via the label attribute." },
  { name: "feature-card", tag: "ce-feature-card", className: "CeFeatureCard", import: "custom-elements-collection/feature-card", category: "ui", group: "Comparison & narrative", description: "Marketing-style feature card. Top: tinted icon disk. Middle: title + slotted body. Bottom: optional CTA — rendered as an <a> when href is set, otherwise a <button> that emits ce-feature-cta. Six color tints adjust the icon disk." },
  { name: "feed", tag: "ce-feed", className: "CeFeed", import: "custom-elements-collection/feed", category: "ui", group: "Content", description: "Container element that sorts and groups ce-feed-entry children (or a data array) into a vertical chronological list. Supports day, week, and month bucket grouping with sticky group headers, newest-first or oldest-first ordering, and a dense spacing mode. Re-groups on every slotchange so streaming entry appends are handled without manual refresh. Two-element pair: ce-feed (container) + ce-feed-entry (item). Accepts both slot children and a data array (CDR-005). Satisfies the ARIA 1.1 feed pattern with role=feed on the container and role=article on each entry." },
  { name: "feedback-bar", tag: "ce-feedback-bar", className: "CeFeedbackBar", import: "custom-elements-collection/feedback-bar", category: "ui", group: "Feedback", description: "Per-item row container that walks its descendants on connect and on every slotchange to set data-ce-subject + data-ce-item on every ce-rating, ce-bookmark, ce-dismiss, and ce-comment that doesn't already declare them. Listens to bubbling change events from those descendants and re-emits a single aggregated ce-feedback-item-state event after every change. Does not stop propagation — the original events still bubble to an ancestor ce-feedback-sink." },
  { name: "feedback-export", tag: "ce-feedback-export", className: "CeFeedbackExport", import: "custom-elements-collection/feedback-export", category: "ui", group: "Feedback", description: "Renders one button per requested format and dispatches a bubbling ce-feedback-export-request event the ancestor ce-feedback-sink handles. Listens to ce-feedback-persisted and ce-feedback-failed events from the sink to flash a transient status line (~1500ms) inside its UI. Layout can be row (default), menu (column), or floating (sticky to viewport bottom)." },
  { name: "feedback-heatmap", tag: "ce-feedback-heatmap", className: "CeFeedbackHeatmap", import: "custom-elements-collection/feedback-heatmap", category: "ui", group: "Feedback", description: "Companion to <ce-feedback-sink>. Listens for ce-feedback-state events on document and renders a horizontal cell bar per item — green (thumbs up), red (thumbs down), blue (bookmarked), amber (dismissed), purple (commented), muted (no signal). Hydrates from any ancestor sink's getState() at connect, then updates incrementally on every state event. Optional inline legend." },
  { name: "feedback-sink", tag: "ce-feedback-sink", className: "CeFeedbackSink", import: "custom-elements-collection/feedback-sink", category: "ui", group: "Feedback", description: "Invisible (display: contents) wrapper that listens for ce-rating-change, ce-bookmark-change, ce-dismiss-change, ce-comment-change, ce-feedback-clear, and ce-feedback-export-request events bubbling through the subtree. Every change is normalized to a FeedbackEvent (schema, subject, item, label, action, value, ts) and pushed into a pending batch flushed per batch-ms. Five transports are supported: localstorage (default), http (with optional localstorage offline-fallback), file (showSaveFilePicker with anchor-download fallback), console, and custom (via the .transportImpl JS-only property). Dispatches ce-feedback-persisted and ce-feedback-failed after each flush, and ce-feedback-state with the freshly aggregated SubjectState. Hydrates from localStorage on connect when the local-storage transport is selected. Implements export-request actions for markdown (clipboard), json (anchor-download), submit (HTTP POST), and clear." },
  { name: "feedback-summary", tag: "ce-feedback-summary", className: "CeFeedbackSummary", import: "custom-elements-collection/feedback-summary", category: "ui", group: "Feedback", description: "Read-only dashboard panel. On connect, walks up to find the nearest ce-feedback-sink, pulls its current state, and (when live) listens to ce-feedback-state events to re-render. Sections are selected via the show attribute (any of: counts, avg, top-liked, top-disliked, distribution). top-n caps the top-N lists; live=false freezes after the initial render. Plain HTML output keyed off --ce-* tokens — does not depend on ce-kpi or any other internal component, keeping the feedback set zero-internal-dep." },
  { name: "field", tag: "ce-field", className: "CeField", import: "custom-elements-collection/field", category: "ui", group: "Forms", description: "Gateway form-field wrapper. Renders a <label> wired to the slotted control, optional help text (aria-describedby), and error text (aria-invalid + aria-describedby). Auto-generates control ids when absent. Required reflects to native required or aria-required. Does not participate in form submission itself." },
  { name: "file-card", tag: "ce-file-card", className: "CeFileCard", import: "custom-elements-collection/file-card", category: "ui", group: "Content", description: "Compact attachment card for use in chat surfaces or message bodies. When `href` is set the whole card becomes an anchor (target=_blank); otherwise it renders a non-interactive group. Type icon is derived from the `type` attribute or, failing that, the file extension; a `thumbnail` URL replaces the icon with an actual preview." },
  { name: "file-upload", tag: "ce-file-upload", className: "CeFileUpload", import: "custom-elements-collection/file-upload", category: "ui", group: "Forms", description: "Static-by-default dropzone with click-to-browse + drag-over highlight + drop handling. The component itself never uploads anything — it only collects a File[] from the native <input type=file> or a DragEvent and emits ce-files. The parent owns transport. Default state is an idle, idiomatic zone with a sensible label and hint (CDR-007); attributes accept, multiple, name, label, hint, disabled are all optional. Multimodal chat composers, profile-photo pickers, and report attach surfaces are the primary use cases." },
  { name: "filter-bar", tag: "ce-filter-bar", className: "CeFilterBar", import: "custom-elements-collection/filter-bar", category: "ui", group: "Comparison & narrative", description: "Chip-style filter bar for interactive filtering. Each option becomes a pressable pill; aria-pressed reflects selection state. Single-select by default; multiple=true allows multi-select with the value attribute holding a comma-joined string. Emits ce-filter-change events. For decorative chip rows in static documents (no events, no aria-pressed state), prefer a `<div>` of `<ce-chip>` elements." },
  { name: "flow", tag: "ce-flow", className: "CeFlow", import: "custom-elements-collection/flow", category: "ui", group: "Comparison & narrative", description: "Step-flow diagram. Boxes separated by arrows; each step can have a caption, step number (n), icon, and a color tint. Vertical attribute stacks boxes top-to-bottom and switches the default arrow from → to ↓. Accepts both JSON mode (steps prop) and slot mode (<ce-flow-step> children); JSON takes priority when non-empty (CDR-005)." },
  { name: "flow-step", tag: "ce-flow-step", className: "CeFlowStep", import: "custom-elements-collection/flow-step", category: "ui", group: "Comparison & narrative", description: "Carries a step number (n), title, optional icon, and optional color tint. Default slot accepts rich body content: paragraphs, lists, links, chips — anything HTML (CDR-002). When nested inside ce-flow the parent reads n/title/icon/color as attributes and consumes the default slot HTML via querySelectorAll — the step itself renders nothing (display:contents). When used standalone it renders a full step card." },
  { name: "frame", tag: "ce-frame", className: "CeFrame", import: "custom-elements-collection/frame", category: "ui", group: "Layout & primitives", description: "Locked aspect-ratio container that constrains img, video, iframe, canvas, and picture children. Supports six standard ratios (1:1, 4:3, 16:9, 21:9, 3:4, golden) and two fill modes (cover crops to fill; contain letterboxes to fit). Pure CSS — no JavaScript required." },
  { name: "gauge", tag: "ce-gauge", className: "CeGauge", import: "custom-elements-collection/gauge", category: "ui", group: "Dashboard", description: "Half-circle meter that visualises one numeric value relative to a range, with a fill arc, the value displayed inside, and an optional target tick mark to indicate a goal threshold. Hovering the gauge surfaces a native browser tooltip with the value, range, and target; the tick itself shows a 'Target: N' tooltip on hover. Pure inline SVG; clamps values outside the range so it stays within the dial." },
  { name: "grid", tag: "ce-grid", className: "CeGrid", import: "custom-elements-collection/grid", category: "ui", group: "Layout & primitives", description: "Responsive grid container. Either uses a fixed column count (cols=2/3/4) or repeat(auto-fit, minmax(min, 1fr)) when auto is set. Below 640px the grid collapses to a single column." },
  { name: "heat-cell", tag: "ce-heat-cell", className: "CeHeatCell", import: "custom-elements-collection/heat-cell", category: "ui", group: "Metrics & charts", description: "Carries a tone (1-5 intensity), a title (tooltip string), and a default slot for rich display content per CDR-002. When nested inside ce-heat-row the parent reads tone and title as attributes and consumes the slot text to build the heatmap data grid — the cell itself renders nothing (display:contents). When used standalone it renders a colored inline-flex box with the palette-blue ramp. Tone maps to alpha 0.05/0.175/0.30/0.425/0.55." },
  { name: "heat-row", tag: "ce-heat-row", className: "CeHeatRow", import: "custom-elements-collection/heat-row", category: "ui", group: "Metrics & charts", description: "Carries a label attribute (Y-axis header) and a default slot for <ce-heat-cell> children. When nested inside ce-heatmap the parent reads label as an attribute and iterates ce-heat-cell children via querySelectorAll — the row itself renders nothing (display:contents). When used standalone it renders a labeled flex row of cells. Non-ce-heat-cell slot children are passed through to light DOM and ignored by the parent's data-resolution path." },
  { name: "heatmap", tag: "ce-heatmap", className: "CeHeatmap", import: "custom-elements-collection/heatmap", category: "ui", group: "Metrics & charts", description: "2D heatmap. Accepts data via two modes (CDR-005): (1) JSON mode — rows/cols/data arrays as JS properties or JSON attributes; (2) slot mode — <ce-heat-row> children each containing <ce-heat-cell> children. Resolution order: data non-empty → JSON mode; else iterate <ce-heat-row> slot children; else empty state. Both modes produce visually identical output for equivalent data. In JSON mode each cell may be a plain number (original API, CDR-008 additive) or a CellInput object { value?, tone?, title? } where tone (1-5) overrides the palette-derived alpha and title becomes the cell tooltip. Palette colors each cell by interpolating the palette token between min and max (auto-detected when max is 0). Cell hover surfaces a focus outline." },
  { name: "hero", tag: "ce-hero", className: "CeHero", import: "custom-elements-collection/hero", category: "ui", group: "Layout & primitives", description: "Page header with eyebrow kicker, gradient-clipped title, lede paragraph, and a stats slot for inline KPIs. Provides a radial-gradient background by default; flat attribute suppresses it." },
  { name: "icon", tag: "ce-icon", className: "CeIcon", import: "custom-elements-collection/icon", category: "ui", group: "Layout & primitives", description: "Themed icon slot. The library deliberately does not ship an icon set; authors drop their preferred SVG, emoji, or icon-font glyph into the default slot and ce-icon normalizes sizing and color inheritance. Slotted <svg> elements have their fill and stroke pinned to currentColor so they tint with the surrounding text. Three discrete sizes (sm/md/lg). Decorative by default; setting label promotes it to role=img with an accessible name." },
  { name: "image", tag: "ce-image", className: "CeImage", import: "custom-elements-collection/image", category: "ui", group: "Content", description: "Themable <figure> wrapping a native <img>. Defaults to lazy loading; on a load error, swaps to a fallback URL when provided or shows a styled error placeholder otherwise. Caption can be set as an attribute or via the named slot. Emits ce-image-error so consumers can log or substitute." },
  { name: "input", tag: "ce-input", className: "CeInput", import: "custom-elements-collection/input", category: "ui", group: "Forms", description: "Token-driven labelled input. Wraps a native <input> so type, required, pattern, and other validation attributes work natively. Renders a label, optional help text, and an error region; aria-invalid + aria-describedby are kept in sync. ce-input fires per keystroke; ce-change fires on blur/Enter." },
  { name: "json", tag: "ce-json", className: "CeJson", import: "custom-elements-collection/json", category: "ui", group: "Content", description: "Lightweight inline JSON viewer for chat surfaces and dashboards. Accepts a JSON string via the `src` attribute or the default slot, formats it with configurable indent, supports max-length truncation, and shows a summary toggle (Object{n} / Array(n)). Malformed input renders a styled error and emits ce-json-parse-error." },
  { name: "kbd", tag: "ce-kbd", className: "CeKbd", import: "custom-elements-collection/kbd", category: "ui", group: "Layout & primitives", description: "Inline primitive for keyboard shortcuts. The slotted text is shown inside a small bordered cap with monospace font and a 1px lower-edge shadow that suggests a physical key. The component carries no attributes by design — multi-key chords compose with regular HTML (drop multiple <ce-kbd> next to each other separated by a plus or hyphen). role=text is set by default so screen readers treat the cap as a single token rather than splitting on punctuation." },
  { name: "key-value", tag: "ce-key-value", className: "CeKeyValue", import: "custom-elements-collection/key-value", category: "ui", group: "Content", description: "Two authoring modes. Mode A (dt/dd): wraps slotted `<dt>/<dd>` pairs in a CSS-grid `<dl>` so keys align in a column — supports 1-3 column-pairs side-by-side. Mode B (ce-kv): when direct children include `<ce-kv>` elements, stacks them in a flex column — values in each row accept any HTML content per CDR-002. If any `<ce-kv>` children are present Mode B is used; otherwise Mode A." },
  { name: "kpi", tag: "ce-kpi", className: "CeKpi", import: "custom-elements-collection/kpi", category: "ui", group: "Metrics & charts", description: "Single-stat KPI block — large value, small uppercase label, and optional inline trend (e.g. '+12%') that auto-colors based on its leading sign (+ green, - red, otherwise neutral). Used inside <ce-hero slot=\"stats\"> or in any grid row." },
  { name: "kv", tag: "ce-kv", className: "CeKv", import: "custom-elements-collection/kv", category: "ui", group: "Content", description: "Single key-value row brick. The `key` attribute is the short label; the default slot carries the value and accepts any HTML content: plain text, `<a>`, `<time>`, `<code>`, `<ce-chip>`, or future typed renderers. Follows CDR-002: values stay in children so typed renderers can compose in later." },
  { name: "link", tag: "ce-link", className: "CeLink", import: "custom-elements-collection/link", category: "ui", group: "Layout & primitives", description: "Light wrapper around <a> that owns the underline/hover/focus treatment for the library. Setting external opens the link in a new tab, appends rel=noopener noreferrer for safety, and shows a small ↗ glyph; setting download forwards the attribute to the underlying <a>. The tone attribute switches between the default underlined link and a subtle in-flow link that only shows its underline on hover." },
  { name: "list", tag: "ce-list", className: "CeList", import: "custom-elements-collection/list", category: "ui", group: "Content", description: "Generic flat list container with configurable dividers, density, and optional interactive hover states. Suitable for notifications, search results, settings rows, and audit logs." },
  { name: "mark", tag: "ce-mark", className: "CeMark", import: "custom-elements-collection/mark", category: "ui", group: "Layout & primitives", description: "Inline highlight primitive used for search-result hits, AI-mentioned entities, or 'this changed' emphasis. Seven CecColor tints (amber default), two emphasis weights (subtle uses a tinted background, strong uses a saturated fill with inverted text). Uses box-decoration-break:clone so the highlight wraps cleanly across line breaks." },
  { name: "matrix", tag: "ce-matrix", className: "CeMatrix", import: "custom-elements-collection/matrix", category: "ui", group: "Comparison & narrative", description: "Decision-analysis primitive that fills the gap between ce-heatmap (cells of values) and ce-pros-cons (two columns). Axes are configurable (defaults: x=Effort, y=Impact) with low/high markers; the four quadrants carry default captions (Quick wins / Big bets / Fill-ins / Money pits) overridable via the q-labels JSON array. Each quadrant is tinted with a different semantic colour so the placement reads at a glance. Items are placed via either a JSON `items` array with explicit quadrant 0..3 or slotted children carrying `data-quadrant=\"0..3\"` (CDR-005 dual mode). Quadrant order is reading-order: 0=TL, 1=TR, 2=BL, 3=BR." },
  { name: "message-group", tag: "ce-message-group", className: "CeMessageGroup", import: "custom-elements-collection/message-group", category: "ui", group: "Chat surfaces", description: "Layout wrapper that renders a group-level avatar and header (author + timestamp) exactly once, then stacks slotted message children with tightened inter-bubble spacing. Role-driven alignment mirrors ce-chat-bubble: user groups align right, all others left. On every slotchange, the group sets the follow-up attribute on every slotted ce-chat-bubble after the first, so each follow-up bubble hides its own avatar column and header line — collapsing repeated chrome in the cluster. Compact mode further reduces the gap. Pure presentation; emits no events." },
  { name: "modal", tag: "ce-modal", className: "CeModal", import: "custom-elements-collection/modal", category: "ui", group: "Layout & primitives", description: "A modal dialog built on the native <dialog> element with showModal(). Provides header with title and optional dismiss button, default body slot, and right-aligned footer slot. Supports ESC and backdrop-click dismissal (guarded by dismissible attribute). Emits ce-modal-open and ce-modal-close events. Returns focus to the invoking element on close." },
  { name: "page", tag: "ce-page", className: "CePage", import: "custom-elements-collection/page", category: "ui", group: "Layout & primitives", description: "Layout primitive that wraps an entire page in a CSS grid with named areas: header (top), nav (sidebar rail, position depends on layout), main (default slot), and footer (bottom). Supports three layouts: stacked (single-column default), sidebar-left, and sidebar-right. Sidebar layouts collapse to stacked below 48rem. Sticky header and sticky footer are opt-in boolean flags. Rail width is configurable via the rail-width attribute." },
  { name: "pagination", tag: "ce-pagination", className: "CePagination", import: "custom-elements-collection/pagination", category: "ui", group: "Layout & primitives", description: "Static-by-default page navigation: renders the current state from page + total, emits ce-pagechange on activation, and only mutates page itself when manage='self' is set (CDR-004 stateful opt-in). The numbered range collapses with ellipses when there are gaps, controlled by the sibling count. A compact mode swaps the number buttons for a 'n / total' info line for tight surfaces." },
  { name: "persona", tag: "ce-persona", className: "CePersona", import: "custom-elements-collection/persona", category: "ui", group: "Comparison & narrative", description: "Persona / role card. Top row shows an emoji-or-character avatar plus name + role; optional `rank` and `score` attributes render as small pills beside the name. Below the head sits a `tags` slot for chips, a `detail` slot for a rich description paragraph, a `meta` slot for `<ce-kv>` metadata rows, and a default slot for arbitrary body content. Six color tints set the top border and avatar/pill tint." },
  { name: "plot", tag: "ce-plot", className: "CePlot", import: "custom-elements-collection/plot", category: "ui", group: "Metrics & charts", description: "Single SVG chart selectable via the `type` attribute (line / area / bar). Accepts a JSON-attribute or property-bound array of `{ name, color?, points: [{ x, y, label? }], hidden? }` series. The x axis auto-detects scale kind from the first point: Date → time, number → linear, string → category. Y axis is linear and uses the shared niceTicks helper for human-readable ticks. Series colors cycle through the shared default palette unless a series declares `color`, which routes through resolveColor() so both named tokens (\"blue\", \"green\", …) and arbitrary CSS colors (\"#5a8\", \"var(--brand)\") are accepted. Vertical bars (the default) support grouped layout and `stacked` mode against a category x scale; horizontal bars swap the axes for category-y / value-x. Hover the chart for a vertical crosshair plus a tooltip card listing every visible series at the snapped x; click a per-series marker to dispatch `ce-chart-select`. Click a legend chip to toggle that series' visibility (`ce-chart-toggle`); the component owns the local hidden state separately from `series.hidden`. The data layer fades in on each render when `animated`; `prefers-reduced-motion` always disables motion regardless of the flag." },
  { name: "popover", tag: "ce-popover", className: "CePopover", import: "custom-elements-collection/popover", category: "ui", group: "Layout & primitives", description: "An anchored, non-modal overlay panel built on the native Popover API. Positions itself relative to a slotted trigger element using JS-computed placement across 8 standard anchor points. Supports light-dismiss via popover=auto, manual mode via popover=manual, an optional directional arrow, and programmatic show/hide/toggle methods. Emits ce-popover-open and ce-popover-close. Returns focus to the trigger on close." },
  { name: "pricing-tier", tag: "ce-pricing-tier", className: "CePricingTier", import: "custom-elements-collection/pricing-tier", category: "ui", group: "Comparison & narrative", description: "A card-shaped pricing tier: badge, tier name, sub-headline, big-number price, feature list (JSON or slot children), and an optional CTA button or link. Use highlighted for the recommended tier. Compose side-by-side via ce-grid instead of a dedicated pricing container (CDR-006)." },
  { name: "progress", tag: "ce-progress", className: "CeProgress", import: "custom-elements-collection/progress", category: "ui", group: "Metrics & charts", description: "Linear progress bar bound by value/max. Supports an optional left label, a numeric percent value on the right (show-value), an indeterminate shimmer, and five color tokens for the fill. Exposes ARIA progressbar semantics with valuemin / valuemax / valuenow / busy." },
  { name: "progress-list", tag: "ce-progress-list", className: "CeProgressList", import: "custom-elements-collection/progress-list", category: "ui", group: "Layout & primitives", description: "Flex-column layout container. Accepts ce-progress rows, narrative paragraphs, ce-callout annotations, and any other children. Gap between rows is controlled by the --ce-progress-list-gap custom property. No hard wrappers — any HTML child renders correctly (CDR-006)." },
  { name: "pros-cons", tag: "ce-pros-cons", className: "CeProsCons", import: "custom-elements-collection/pros-cons", category: "ui", group: "Comparison & narrative", description: "Decision-analysis primitive that replaces the ad-hoc 'ce-compare for pros/cons' workaround surfaced in audit. Two columns: left=pros (green accent, ✓ markers), right=cons (red accent, ✗ markers). Each side accepts either a JSON array of strings (CDR-005 JSON mode) or slotted <li> / arbitrary children (slot mode), and the two modes may be mixed (JSON pros + slotted cons). Headers default to 'Pros' / 'Cons' and accept attribute overrides for localised or domain-specific phrasing ('Benefits' / 'Risks', 'Plusy' / 'Minusy', etc.). Stacks to a single column below ~540 px." },
  { name: "qr", tag: "ce-qr", className: "CeQr", import: "custom-elements-collection/qr", category: "ui", group: "Content", description: "Pure-SVG QR code. The full ISO/IEC 18004 encoder ships in the bundle (byte mode, versions 1-40, error-correction levels L/M/Q/H). Auto-picks the smallest version that fits the data, picks the optimal mask via penalty scoring, and emits a single <path> with merged horizontal runs. Fully themable via --ce-qr-fg / --ce-qr-bg. No CDN, no canvas, no QR library." },
  { name: "quote", tag: "ce-quote", className: "CeQuote", import: "custom-elements-collection/quote", category: "ui", group: "Comparison & narrative", description: "Blockquote component used in research, customer development, B2B reports, and persona documents. Wraps a native <blockquote> and <cite> for correct ARIA semantics. Attribution accepts plain text via attributes (author, source) or rich markup via named slots — links, time elements, chips. Three variants cover the most common corpus patterns: card (purple left-border block), pull (oversized centered pull-quote), and inline (indented prose blockquote)." },
  { name: "radio-group", tag: "ce-radio-group", className: "CeRadioGroup", import: "custom-elements-collection/radio-group", category: "ui", group: "Forms", description: "Radio-group with three visual treatments: 'classic' (traditional radio circles), 'segmented' (joined-button group), and 'card' (option-as-card with optional hint line). Roving tabindex; arrow keys + Home/End move selection; Space/Enter activate. Options provided as a JSON array; per-option disabled state honored. Emits ce-change with { name, value }." },
  { name: "rank-list", tag: "ce-rank-list", className: "CeRankList", import: "custom-elements-collection/rank-list", category: "ui", group: "Comparison & narrative", description: "Static-by-default ranking primitive for leaderboards, top-N reports, and ordered priorities. Position numbers are computed from list order (#1, #2, …) so authors don't renumber on reorder; an offset start attribute lets the list begin at any rank. Optional score column right-aligns numeric or string values; optional delta column shows ▲ / ▼ / — movement coloured by direction. By default the top three items are accented with medal colours (gold / silver / bronze); pass `flat` to disable. Accepts JSON items or slotted <li> children (CDR-005); in slot mode the rank is rendered as a counter prefix." },
  { name: "rating", tag: "ce-rating", className: "CeRating", import: "custom-elements-collection/rating", category: "ui", group: "Chat surfaces", description: "Two-mode feedback control. **Supports static read-only display via `readonly` — the first example demonstrates this canonical vis-document usage (CDR-004).** In thumbs mode, two side-by-side buttons toggle between up/down/null with aria-pressed. In stars mode, max buttons form a radiogroup with optional half-star precision via pointermove offset, click-to-clear, and arrow-key navigation. Form-associated via ElementInternals so the resolved value participates in surrounding <form> submissions when name is set. Emits ce-rating-change with a uniform detail shape when interactive." },
  { name: "reasoning", tag: "ce-reasoning", className: "CeReasoning", import: "custom-elements-collection/reasoning", category: "ui", group: "Chat surfaces", description: "Disclosure widget for displaying chain-of-thought traces produced by reasoning-capable models (e.g. Claude thinking blocks, o1-style reasoning). The header shows a chevron, a configurable label, an optional streaming pulse dot, optional token count, and optional humanised duration. The body panel holds slotted reasoning content styled muted and italic to visually separate it from the main response. Implements disclosure semantics with a real button carrying aria-expanded and aria-controls; does not wrap native <details> so the max-height CSS transition is consistent across browsers." },
  { name: "recommendation", tag: "ce-recommendation", className: "CeRecommendation", import: "custom-elements-collection/recommendation", category: "ui", group: "Comparison & narrative", description: "Card-like block that encodes a single actionable recommendation. A four-value priority enum (p0–p3) drives the left-border color and the visible priority badge. Title and impact accept both plain string attributes and rich slot overrides (CDR-002). Body accepts arbitrary children. An optional actions slot holds call-to-action buttons or links." },
  { name: "relative-time", tag: "ce-relative-time", className: "CeRelativeTime", import: "custom-elements-collection/relative-time", category: "ui", group: "Layout & primitives", description: "Renders a semantic <time datetime='...'> element whose text content is the difference between the supplied datetime and now, formatted via Intl.RelativeTimeFormat with the largest sensible unit (seconds → minutes → hours → days → months → years). Self-rescheduling: it ticks every second while under a minute old, every 30 seconds while under an hour, then larger steps to keep CPU and battery low for older items." },
  { name: "retry-button", tag: "ce-retry-button", className: "CeRetryButton", import: "custom-elements-collection/retry-button", category: "ui", group: "Chat surfaces", description: "Compact button rendered in three styled variants (primary/secondary/ghost). Default content is a circular-arrow SVG plus the label, both replaceable via the default slot. Emits a bubbling, composed ce-retry CustomEvent on click — no detail payload." },
  { name: "score", tag: "ce-score", className: "CeScore", import: "custom-elements-collection/score", category: "ui", group: "Metrics & charts", description: "Small inline pill showing a numeric score with semantic color coding: green for high, amber for med, red for low. Tier auto-computes from value/max (default max=10 matches the dominant 0–10 corpus scale). Explicit tier attribute overrides auto-computation. Global thresholds are overridable via --ce-score-breakpoints. Exposes role=meter ARIA semantics." },
  { name: "search", tag: "ce-search", className: "CeSearch", import: "custom-elements-collection/search", category: "ui", group: "Forms", description: "Form-associated search input with shadow DOM layout. Renders a flex row: magnifier icon, native search input, clear button (visible when value is non-empty), optional spinner (loading state), and optional shortcut hint chip. Fires ce-search (debounced) on value change and ce-submit immediately on Enter. Attaches a document-level keydown listener for the optional shortcut attribute, skipping the handler when focus is inside another editable element." },
  { name: "section", tag: "ce-section", className: "CeSection", import: "custom-elements-collection/section", category: "ui", group: "Layout & primitives", description: "Titled content section. Renders a header row containing an optional circular number badge, a heading, and an optional count chip on the right; underneath the row sits an optional lede paragraph and the default body slot. Used to break long pages into numbered chapters." },
  { name: "segmented", tag: "ce-segmented", className: "CeSegmented", import: "custom-elements-collection/segmented", category: "ui", group: "Forms", description: "Joined-button segmented control backed by a radiogroup ARIA role. Accepts segments either as JSON via the data attribute (data-array mode) or as ce-segment child elements (slot-child mode); slot children win when both are present. Roving tabindex: only the selected segment (or the first when none is selected) is reachable via Tab; ArrowRight/ArrowLeft move selection with wrap-around. Form-associated; sets internal form value on every selection change. Emits ce-change with { name, value }." },
  { name: "select", tag: "ce-select", className: "CeSelect", import: "custom-elements-collection/select", category: "ui", group: "Forms", description: "Form-primitive companion to ce-input wrapping a native <select> for full keyboard, screen-reader, and OS-popup behaviour. Options accept the dual-mode CDR-005 shape — a JSON-on-attribute array or slotted <option>/<optgroup> children. Mirrors ce-input's label / help / error / prefix-suffix layout so forms compose consistently. Emits ce-change on selection." },
  { name: "shell", tag: "ce-shell", className: "CeShell", import: "custom-elements-collection/shell", category: "ui", group: "Layout & primitives", description: "Page-level wrapper. Clamps content width (narrow / default / wide / full), applies the project's outer padding, and propagates the active theme to the document root via data-ce-theme so token CSS resolves correctly. Should be used at most once per page." },
  { name: "skeleton", tag: "ce-skeleton", className: "CeSkeleton", import: "custom-elements-collection/skeleton", category: "ui", group: "Layout & primitives", description: "Loading placeholder with text-line, rectangle, and circle shapes. The text variant supports multiple lines with the last line shortened to mimic real prose. Decoration is hidden from assistive technology via aria-hidden." },
  { name: "source-card", tag: "ce-source-card", className: "CeSourceCard", import: "custom-elements-collection/source-card", category: "ui", group: "Chat surfaces", description: "Panel companion to ce-citation. While ce-citation lives inline inside prose, ce-source-card is the list / sidebar artefact answering 'what did the model retrieve'. Wraps the title in <a target=_blank> when url is set, derives the site label from the URL host when site is omitted, and renders a relevance score normalising both 0..1 and 0..100 inputs to a percent display. Snippet text goes in the default slot; an optional [n] index threads into inline citations." },
  { name: "sparkline", tag: "ce-sparkline", className: "CeSparkline", import: "custom-elements-collection/sparkline", category: "ui", group: "Dashboard", description: "Compact inline SVG chart for trend visualisation in a row, table cell, or KPI tile. Supports line (default), filled area, and bar shapes; auto-scales to the value range. Values can be supplied four ways (resolution order): (1) JSON-encoded `values` attribute, (2) JS property, (3) a <ce-data> child carrying a {values:[…]} or bare-array JSON payload (CDR-5 advanced shape — useful when the payload is too big or escaping-heavy for an attribute), (4) whitespace- or comma-separated numbers in the element's own text content. The earliest source with data wins. Child-content streaming is supported via MutationObserver, so values appended after upgrade re-render." },
  { name: "spinner", tag: "ce-spinner", className: "CeSpinner", import: "custom-elements-collection/spinner", category: "ui", group: "Feedback", description: "Pure CSS spinning ring used as an inline loading atom below ce-skeleton and ce-loading-state. Supports four sizes, three tones, and reduced-motion fallback (slow fade pulse). Carries role=status and aria-label for screen reader announcements." },
  { name: "stack", tag: "ce-stack", className: "CeStack", import: "custom-elements-collection/stack", category: "ui", group: "Layout & primitives", description: "Flex container that uses gap to enforce consistent spacing between direct children. Supports vertical and horizontal direction, eight space-scale steps, optional wrap (former ce-cluster behavior), cross-axis align (start/center/end/baseline/stretch), main-axis justify (start/center/end/between), a recursive propagation mode, and a split-after trick (Heydon Pickering's sticky-footer pattern) that pushes the Nth+1 child to the far end via margin-block-start: auto." },
  { name: "stat-group", tag: "ce-stat-group", className: "CeStatGroup", import: "custom-elements-collection/stat-group", category: "ui", group: "Dashboard", description: "**Deprecated** — use `<ce-grid>` with `<ce-kpi>` children instead. Will be removed in next minor (see ADR-010). Grid wrapper that arranges KPI tiles (or any cells) with a consistent gutter. Choose a fixed column count (2-6) or 'auto' for a fit-content layout that breaks into rows on narrow viewports. Pairs with <ce-kpi>, but tolerates any child element." },
  { name: "status-light", tag: "ce-status-light", className: "CeStatusLight", import: "custom-elements-collection/status-light", category: "ui", group: "Dashboard", description: "Compact status indicator for dashboards, lists, and report rows. Five states (ok/warn/bad/neutral/pending) map to semantic color tokens, an optional pulse animation highlights live activity, and the label is provided either via the label attribute or the default slot. Use `ce-status-light` when `pulse` animation is needed (live dashboards); use `<ce-chip dot>` for static state in documents (overlap is intentional but the cases split on whether motion is desired)." },
  { name: "step", tag: "ce-step", className: "CeStep", import: "custom-elements-collection/step", category: "ui", group: "Comparison & narrative", description: "A single step brick for process / roadmap / onboarding flows. Displays a 32px circle disk (number or check), a title row with optional inline metadata, and a description area. State enum (pending|active|done) drives disk color and title weight via CSS custom properties — no domain vocabulary in the enum (CDR-001). Default slot carries rich description content (CDR-002). Slot=\"title\" overrides the title attribute for rich inline content. Can be used standalone or nested inside ce-steps (CDR-006); the parent auto-assigns n when auto-number is enabled." },
  { name: "steps", tag: "ce-steps", className: "CeSteps", import: "custom-elements-collection/steps", category: "ui", group: "Comparison & narrative", description: "Layout container for process / roadmap steps implementing CDR-005 dual-mode: JSON array via the data attribute takes priority; slot children are used otherwise; empty state rendered when neither is present. When auto-number is enabled (default), sequential numbers are assigned to ce-step children that have no n attribute. Non-ce-step slot children are passed through without interference (CDR-006). Direction (vertical|horizontal) controls the flex axis. In JSON mode the container creates ce-step elements inline from the data array, producing visually identical output to the equivalent slot markup." },
  { name: "stop-button", tag: "ce-stop-button", className: "CeStopButton", import: "custom-elements-collection/stop-button", category: "ui", group: "Chat surfaces", description: "Compact button rendered in three styled variants (primary/secondary/ghost). Default content is a stop-square SVG plus the label, both replaceable via the default slot. Emits a bubbling, composed ce-chat-stop CustomEvent on click or Enter/Space — no event fired when disabled." },
  { name: "stream-status", tag: "ce-stream-status", className: "CeStreamStatus", import: "custom-elements-collection/stream-status", category: "ui", group: "Chat surfaces", description: "Compact inline pill that communicates LLM streaming connection state via a color-coded background, border, and animated dot. Optionally renders a formatted token count and a tokens-per-second readout alongside the state label. Sets role=status + aria-live=polite so assistive technology announces state changes." },
  { name: "suggestion-chip", tag: "ce-suggestion-chip", className: "CeSuggestionChip", import: "custom-elements-collection/suggestion-chip", category: "ui", group: "Chat surfaces", description: "Interactive pill-shaped chip designed for chat surfaces. Emits a ce-suggestion-select event carrying the prompt value when clicked or activated via keyboard. Distinct from ce-chip (non-interactive status display): suggestion-chip is an intent primitive — it initiates user action. Supports disabled and selected states, an optional leading icon attribute, and a named icon slot for richer overrides." },
  { name: "table", tag: "ce-table", className: "CeTable", import: "custom-elements-collection/table", category: "ui", group: "Layout & primitives", description: "Light-DOM-aware wrapper around a slotted <table>. Adds surface border, radius, horizontal scroll container, and ambient styles for headers, cells, hover, and special td classes (.num, .center, .mono). Sticky and compact attributes are honored via the ambient stylesheet." },
  { name: "tabs", tag: "ce-tabs", className: "CeTabs", import: "custom-elements-collection/tabs", category: "ui", group: "Layout & primitives", description: "Tabbed content widget for interactive production UX. The head reuses the same chip-pill visual style as ce-filter-bar (one family across the catalog). Two ways to provide tab labels: a JSON tabs[] prop (string or {label, badge?, disabled?}) for the data path, or slotted <button slot=\"tab\"> children for richer markup. Panels always come from <* slot=\"panel\"> children, paired with tabs by index. Roving tabindex; arrow keys / Home / End move selection; Space / Enter activate. Aria-selected, aria-controls, aria-labelledby connect tabs to panels. For static anchored sections in a vis-style document, prefer <ce-section> + <ce-toc>." },
  { name: "tag", tag: "ce-tag", className: "CeTag", import: "custom-elements-collection/tag", category: "ui", group: "Layout & primitives", description: "Distinct from ce-chip (which is a status pip): ce-tag is a content-categorisation token used for tag clouds, multi-select filter facets, and topical labels. Leads with a faded # glyph for visual recognition. Seven CecColor tints (neutral default), and an optional × button that emits ce-tag-remove with the optional value identifier in the event detail. The label itself is slotted (vocabulary lives in children per CDR-001)." },
  { name: "textarea", tag: "ce-textarea", className: "CeTextarea", import: "custom-elements-collection/textarea", category: "ui", group: "Forms", description: "Themed multi-line input. Auto-grows up to max-rows on input, then becomes scrollable. Renders an optional label, help text, or error message; aria-invalid and aria-describedby stay in sync. ce-input fires per keystroke; ce-change fires on blur/commit." },
  { name: "thinking", tag: "ce-thinking", className: "CeThinking", import: "custom-elements-collection/thinking", category: "ui", group: "Chat surfaces", description: "Compact typing indicator with three animation variants (dots, wave, spinner) and a configurable label. The host element is role=status with aria-live=polite so assistive tech announces appearance and disappearance." },
  { name: "timeline", tag: "ce-timeline", className: "CeTimeline", import: "custom-elements-collection/timeline", category: "ui", group: "Comparison & narrative", description: "Timeline of TimelineItem entries. Each item has a title, optional meta line (date/duration/owner), optional description, optional color for the dot, and optional icon character. Vertical (default) renders a connecting rail; horizontal renders a row of equally-sized columns." },
  { name: "toc", tag: "ce-toc", className: "CeToc", import: "custom-elements-collection/toc", category: "ui", group: "Layout & primitives", description: "Table of contents component. Accepts an entries array of { href, label } via property or JSON attribute; optionally numbers each entry and sticks to the top of its scroll parent. When entries is empty, falls back to the default slot so consumers can supply <a> children directly." },
  { name: "toggle", tag: "ce-toggle", className: "CeToggle", import: "custom-elements-collection/toggle", category: "ui", group: "Forms", description: "Switch-style boolean control. Click, Enter, or Space toggles state. The host carries role=switch and aria-checked, so screen readers announce changes correctly. Pairs nicely as the right edge of a labelled row." },
  { name: "tool-call", tag: "ce-tool-call", className: "CeToolCall", import: "custom-elements-collection/tool-call", category: "ui", group: "Chat surfaces", description: "Disclosure widget purpose-built for function-calling and MCP-call visibility. The header shows a status dot (running pulses; ok/error are static), the tool name in monospace, and a humanized duration. Clicking toggles a body panel that always renders args, plus result (status=ok) or error (status=error). Implements the disclosure semantics manually (header has aria-expanded + aria-controls) rather than wrapping native <details>, so styling is consistent across browsers." },
  { name: "tool-result", tag: "ce-tool-result", className: "CeToolResult", import: "custom-elements-collection/tool-result", category: "ui", group: "Chat surfaces", description: "Pure-presentation brick for showing an agent tool return value without the collapsible call header. A coloured left border keys off status: green for ok, red for error, neutral border for empty. When name or duration-ms are provided, a compact monospace header row appears above the content. The default slot holds the result payload; when status='error' the payload area is replaced by the named 'error' slot. A meta slot adds an optional footer row (e.g. a cached/streamed chip). When status='empty' and the default slot has no assigned content, a muted '(no result)' placeholder renders. The compact boolean tightens padding for inline-trace contexts." },
  { name: "tooltip", tag: "ce-tooltip", className: "CeTooltip", import: "custom-elements-collection/tooltip", category: "ui", group: "Feedback", description: "A non-interactive tooltip anchored to an external target element by id. Uses the native Popover API (popover=manual) for top-layer rendering. Shows after a configurable delay on mouseenter or focusin; hides immediately on mouseleave or focusout. Positions itself via JS getBoundingClientRect across four placements (top, bottom, left, right). Wires aria-describedby on the target when visible." },
  { name: "tree", tag: "ce-tree", className: "CeTree", import: "custom-elements-collection/tree", category: "ui", group: "Content", description: "Generic interactive tree with keyboard navigation (ARIA tree pattern) and roving tabindex. Accepts either slot-children (<ce-tree-node> recursively) or a JSON data array. The sibling element <ce-tree-node> provides the per-node rendering with chevron, label slot, and nested children group." },
  { name: "verdict", tag: "ce-verdict", className: "CeVerdict", import: "custom-elements-collection/verdict", category: "ui", group: "Comparison & narrative", description: "Decision banner with icon, title, and detail. Four semantic types tint the border, background, icon, and title color. Default icons are ✓ ✗ ⚠ ℹ; consumers can override via the icon attribute or supply custom title markup via the title slot." },
  { name: "lesson-audio", tag: "lesson-audio", className: "LessonAudio", import: "custom-elements-collection/lesson-audio", category: "lesson", group: "Education", description: "Pronunciation / audio-clip button. Renders a play button (label is configurable, default '🔊 Play') plus an optional monospace phonetic string. First click instantiates a single HTMLAudioElement and plays it; subsequent plays reuse the same element. Error states show inline." },
  { name: "lesson-compare", tag: "lesson-compare", className: "LessonCompare", import: "custom-elements-collection/lesson-compare", category: "lesson", group: "Education", description: "Renders a two-column grid with labeled headers and named slots. Three modes: neutral (default), correct-wrong (left red, right green labels), before-after (left muted, right blue labels). Mode reflects on host for CSS selector targeting." },
  { name: "lesson-confidence", tag: "lesson-confidence", className: "LessonConfidence", import: "custom-elements-collection/lesson-confidence", category: "lesson", group: "Education", description: "Metacognitive rating widget with 5 circular buttons. The label prop sets the prompt. Clicking a button sets rating, marks the card submitted (attribute reflects), disables all other buttons, and fires lesson-confidence-rate. reset() clears state. Supports Bjork's desirable-difficulty framework." },
  { name: "lesson-frame", tag: "lesson-frame", className: "LessonFrame", import: "custom-elements-collection/lesson-frame", category: "lesson", group: "Education", description: "Top-level lesson shell. Renders a fixed 4px progress bar at the top of the viewport (driven by the progress prop), a centered title + meta row, and a content column with a max-width of 880px. Used as the outermost element on a lesson page." },
  { name: "lesson-gap", tag: "lesson-gap", className: "LessonGap", import: "custom-elements-collection/lesson-gap", category: "lesson", group: "Education", description: "Fill-in-the-blank exercise. Splits the prompt at the first '___' marker and renders the gap as a colored span; below sit the options as buttons. After the user picks, the chosen button colors green or red, the gap fills with the correct answer when correct, and a feedback strip shows the explanation. lesson-gap-answer fires once per exercise." },
  { name: "lesson-hint", tag: "lesson-hint", className: "LessonHint", import: "custom-elements-collection/lesson-hint", category: "lesson", group: "Education", description: "Shows a 'Show hint N of M' button. Each click reveals the next hint in a stacked list. The most recently revealed hint has a blue highlight. After all hints are shown the button changes to 'All hints shown' and disables. Fires lesson-hint-show with {index, hint} on each reveal. Accepts hints as a JSON string[] attribute." },
  { name: "lesson-match", tag: "lesson-match", className: "LessonMatch", import: "custom-elements-collection/lesson-match", category: "lesson", group: "Education", description: "Renders two columns of buttons. Learner clicks one item on the left, then one on the right; correct pairs lock in green and disable, wrong pairs flash red and clear the selection. The right column is shuffled deterministically so the order does not encode the answer. After every pair is matched, the host gets the submitted attribute and lesson-match-complete fires once with the attempt count. lesson-match-pair fires on every click-pair attempt with { left, right, correct }. Accepts pairs as a JSON [{ left, right }, ...] attribute or property." },
  { name: "lesson-myth", tag: "lesson-myth", className: "LessonMyth", import: "custom-elements-collection/lesson-myth", category: "lesson", group: "Education", description: "Shows a red-tinted myth card with a '✗ Myth' badge and the false belief. On click, flips to a green-tinted truth card with '✓ Truth' badge and the correct statement. Optional explanation shown below truth. Fires lesson-myth-reveal once on first reveal. reset() returns to myth view." },
  { name: "lesson-note", tag: "lesson-note", className: "LessonNote", import: "custom-elements-collection/lesson-note", category: "lesson", group: "Education", description: "Renders a left-bordered, tinted callout block with an auto-selected icon based on type. The icon can be overridden. Five types supported: tip (blue), info (cyan), key (amber), warning (amber), danger (red)." },
  { name: "lesson-option", tag: "lesson-option", className: "LessonOption", import: "custom-elements-collection/lesson-option", category: "lesson", group: "Education", description: "Light-content multiple-choice option. By default renders as a static row (marker + text) so it works inside read-only study guides and vis documents. When the parent question opts in to interactive mode, lesson-option flips to a clickable <button> and emits lesson-option-pick with { value, correct } on click. The picked + revealed + correct attributes together drive the post-pick visual state (green check on correct, red ✗ on picked-but-wrong); the parent question is responsible for setting them. Text content comes from the default slot — typed renderers (<code>, <a>, <time>) compose freely (CDR-002)." },
  { name: "lesson-question", tag: "lesson-question", className: "LessonQuestion", import: "custom-elements-collection/lesson-question", category: "lesson", group: "Education", description: "Renders a prompt followed by a default slot of <lesson-option> children (and any inline hints like <lesson-note>). In static mode the correct option is revealed on render, which suits read-only study guides and vis documents. When the interactive attribute is set, options flip to clickable; on the first lesson-option-pick the question locks all options, marks picked + correct, fires lesson-question-answer with { value, correct, index }, and reflects the answered attribute on the host. reset() clears the state. The component listens for lesson-option-pick from slotted lesson-option children and decides what to do — lesson-option is a passive renderer driven by the question." },
  { name: "lesson-quickfire", tag: "lesson-quickfire", className: "LessonQuickfire", import: "custom-elements-collection/lesson-quickfire", category: "lesson", group: "Education", description: "Timed practice round. Cycles through QuickfireRound entries; each round shows the prompt, options, and a thin timer bar that empties over `timer` seconds. If a round has `correct`, picks flash green/red and count toward the score; if `correct` is omitted (poll/opinion round), the picked option flashes neutral and the round is excluded from the score. After the last round emits lesson-quickfire-done; reset() restarts. Final screen shows `score / scoredRoundCount`, or just `Done!` when no round was scored." },
  { name: "lesson-quiz", tag: "lesson-quiz", className: "LessonQuiz", import: "custom-elements-collection/lesson-quiz", category: "lesson", group: "Education", description: "Two-shape multiple-choice quiz. In the single-question shape, set question/options/correct/explanation; clicking an option marks it green if correct or red if wrong (and outlines the correct one), shows the explanation, and disables the rest. lesson-quiz-answer fires once. In the container shape, leave question empty and slot one or more <lesson-question> children; each manages its own answer state via lesson-question-answer. Setting interactive on the quiz cascades the attribute to every direct <lesson-question> child so a whole batch can be opted in with one attribute (CDR-004). The container attribute auto-reflects when question is empty and drops the panel chrome so the questions provide their own framing." },
  { name: "lesson-reveal", tag: "lesson-reveal", className: "LessonReveal", import: "custom-elements-collection/lesson-reveal", category: "lesson", group: "Education", description: "Single-card flashcard widget. Displays front-label + front text with a 'Click to reveal' hint. On click, flips to show back-label (green) + back text + reset hint. Fires lesson-reveal-flip on each flip. reset() returns to front state. Entire card is clickable." },
  { name: "lesson-rule", tag: "lesson-rule", className: "LessonRule", import: "custom-elements-collection/lesson-rule", category: "lesson", group: "Education", description: "Rule card for educational content. Top row shows a circular blue badge (number / glyph / ★) plus a title; below sits a slotted body. golden=true switches to amber styling for emphasized, top-of-lesson rules." },
  { name: "lesson-step", tag: "lesson-step", className: "LessonStep", import: "custom-elements-collection/lesson-step", category: "lesson", group: "Education", description: "Renders a circular badge with the step number (or checkmark when done), alongside a title and slotted body. Status drives badge color: pending=muted, active=blue, done=green. Done status strikes through the title." },
  { name: "lesson-summary", tag: "lesson-summary", className: "LessonSummary", import: "custom-elements-collection/lesson-summary", category: "lesson", group: "Education", description: "Renders an amber-bordered card with a title and either a JSON-driven checklist (items prop) or slotted content. Each item gets a green checkmark prefix. Default title is 'Key Takeaways'. When items is empty the default slot renders instead." },
  { name: "lesson-vocab", tag: "lesson-vocab", className: "LessonVocab", import: "custom-elements-collection/lesson-vocab", category: "lesson", group: "Education", description: "Fully prop-driven vocabulary card. Shows the term in large bold text, optional phonetic in monospace, optional pos badge (amber), optional level badge (muted). Definition and example sentence below. Suitable for language learning and technical terminology. No slots — all content is prop-driven for LLM-friendly markup." },
  { name: "data", tag: "ce-data", className: "CeData", import: "custom-elements-collection/data", category: "internal", group: "Content", description: "Hidden primitive whose textContent is parsed as JSON and exposed via the .data getter. The element renders nothing (display:none) and acts purely as a data carrier — consumers read `:scope > ce-data` and parse its content. Use this when (a) the payload is too big or contains characters hostile to HTML attributes (quotes, newlines, angle brackets), (b) multiple structured fields are needed (values + labels + baselines), or (c) the producing pipeline naturally emits JSON inline. Invalid JSON returns null and emits a console.warn — no exceptions thrown. Consuming widgets that support this shape include ce-sparkline (parses .values from the payload)." },
  { name: "docs-layout", tag: "ce-docs-layout", className: "CeDocsLayout", import: "custom-elements-collection/docs-layout", category: "internal", group: "Docs", description: "Internal composition primitive for documentation pages. Three slots: header (full-width sticky bar), sidebar (left sticky column, typically <ce-nav-list>), and default (main scrollable area). The sidebar collapses below 760px. sidebar-width attribute sets the column width." },
  { name: "nav-list", tag: "ce-nav-list", className: "CeNavList", import: "custom-elements-collection/nav-list", category: "internal", group: "Docs", description: "Grouped sidebar nav. Items group themselves by their group field; the entry whose href matches value is marked aria-current=page and tinted blue. Each click dispatches ce-nav-select with the href before native navigation runs. Each item may carry an optional `meta` HTML string rendered as a right-aligned secondary block on the row — intended for trust-controlled badges like <ce-clock> or <ce-chip>." },
  { name: "theme-switcher", tag: "ce-theme-switcher", className: "CeThemeSwitcher", import: "custom-elements-collection/theme-switcher", category: "internal", group: "Docs", description: "Compact cycler + dropdown. Layout: ‹ [ Current Label ▾ ] ›. Left/right arrows step through options; the label toggles a grouped dropdown; ArrowLeft/Right and Escape are handled inside the widget. The component is generic — it does not itself touch document themes; consumers wire the ce-change event to whatever they want updated." },
];

/**
 * Dynamic on-demand loader — resolves a subset of components by tag or name
 * via native ESM `import()`. Bundlers tree-shake the unused branches.
 *
 *   await loadOnDemand(["ce-hero", "ce-kpi"]);
 *   await loadOnDemand("lesson-rule");
 */
export async function loadOnDemand(
  selection: string | ReadonlyArray<string>
): Promise<void> {
  const wanted = typeof selection === "string" ? [selection] : selection;
  const set = new Set(wanted);
  const matched = COMPONENTS.filter(
    (c) => set.has(c.tag) || set.has(c.name)
  );
  await Promise.all(matched.map((c) => import(/* @vite-ignore */ c.import)));
}

/** Filter helper: all UI components. */
export const UI_COMPONENTS = COMPONENTS.filter((c) => c.category === "ui");

/** Filter helper: all lesson components. */
export const LESSON_COMPONENTS = COMPONENTS.filter((c) => c.category === "lesson");

/** Filter helper: all internal / layout components. */
export const INTERNAL_COMPONENTS = COMPONENTS.filter((c) => c.category === "internal");
